head.script:
window.dataLayer = window.dataLayer || [];
function gtag(){dataLayer.push(arguments);}
gtag('js', new Date());
gtag('config', 'G-2R14ZESQ0R');

body.script:
document.getElementById('contact-form').addEventListener('submit', async function(e){
  e.preventDefault();

  // Clear previous errors
  document.querySelectorAll('.field-error').forEach(el => el.remove());

  const btn = document.getElementById('submit-btn');
  const form = e.target;

  // Validate
  let valid = true;
  ['name','email','reason','message'].forEach(id => {
    const el = document.getElementById(id);
    if(!el.value || el.value.trim() === ''){
      valid = false;
      const err = document.createElement('div');
      err.className = 'field-error';
      err.textContent = 'Required';
      el.parentElement.appendChild(err);
    }
  });
  if(!valid) return;

  btn.disabled = true;
  btn.textContent = 'Sending...';

  const data = {
    name: document.getElementById('name').value,
    email: document.getElementById('email').value,
    reason: document.getElementById('reason').value,
    message: document.getElementById('message').value,
    _subject: 'Contact — ' + document.getElementById('name').value + ' — ' + document.getElementById('reason').value
  };

  try {
    const res = await fetch('https://formspree.io/f/mnjrvbpn', {
      method: 'POST',
      headers: {'Content-Type':'application/json','Accept':'application/json'},
      body: JSON.stringify(data)
    });

    if(res.ok){
      form.querySelectorAll('input,textarea,select,button').forEach(el => el.style.display = 'none');
      document.querySelector('.submit-note').style.display = 'none';
      document.querySelector('.divider').style.display = 'none';
      document.getElementById('success-box').style.display = 'block';
    } else {
      btn.disabled = false;
      btn.textContent = 'Send Message';
      alert('Something went wrong. Please try again or email editor@quietpremium.com directly.');
    }
  } catch(err){
    btn.disabled = false;
    btn.textContent = 'Send Message';
    alert('Something went wrong. Please email editor@quietpremium.com directly.');
  }
});
